// Tiny in-memory event-sourcing sketch
const store = new Map(); // aggregateId -> events[]
const projections = { orders: new Map() };

function publish(event) {
  // naive synchronous publish
  if (event.type === 'ItemAdded') {
    const order = projections.orders.get(event.aggregateId) || { total: 0, items: [] };
    order.items.push(event.payload);
    order.total += event.payload.price * event.payload.qty;
    projections.orders.set(event.aggregateId, order);
  }
}

function appendEvent(aggregateId, event) {
  event.aggregateId = aggregateId;
  const arr = store.get(aggregateId) || [];
  arr.push(event);
  store.set(aggregateId, arr);
  publish(event);
}

function handleAddItem(cmd) {
  if (cmd.qty <= 0) throw new Error('qty must be > 0');
  appendEvent(cmd.orderId, { type: 'ItemAdded', payload: { itemId: cmd.itemId, qty: cmd.qty, price: cmd.price }, ts: Date.now() });
}

// Use
handleAddItem({ orderId: 'o1', itemId: 'sku1', qty: 2, price: 10 });
console.log(projections.orders.get('o1'));
